const items = $input.all();
const out = [];
for (const it of items) {
  const msg = it.json;
  const fromAddr = (msg.from?.value?.[0]?.address || msg.from || '').toString();
  const lower = fromAddr.toLowerCase();
  if (!lower.includes('immo')) continue;
  const subject = msg.subject || '(sans objet)';
  const date = msg.date || new Date().toISOString();
  const bodyTextRaw = (msg.text || msg.snippet || '').toString();
  const bodyText = bodyTextRaw
    .replace(/<[^>]+>/g, '')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&euro;/g, '€')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/\s+\n/g, '\n')
    .trim()
    .slice(0, 10000);
  const raw_email = 'FROM: ' + fromAddr + '\nSUBJECT: ' + subject + '\nDATE: ' + date + '\n\n' + bodyText;
  out.push({ json: { from: fromAddr, subject, received_at: date, body_text: bodyText, raw_email } });
}
return out;

const items = $input.all();
const sources = $('Filter & Normalize').all();
const out = [];
const T = new Set(['visite','info','candidature','autre']);
const L = new Set(['fr','nl','en']);
function empty(r){return{prospect_nom:null,prospect_email:null,prospect_tel:null,bien_reference:null,bien_adresse:null,type_demande:'autre',langue:'fr',message_prospect:null,score_confiance:0,draft_reply:null,_err:r};}
for (let idx = 0; idx < items.length; idx++) {
  const i = items[idx];
  const sourceIdx = i.pairedItem?.item ?? idx;
  const r = sources[sourceIdx]?.json.raw_email || '';
  let c = '';
  try { c = i.json.choices?.[0]?.message?.content || ''; } catch(x){ out.push({json:{...empty('no_content'),raw_email:r}}); continue; }
  if (!c.trim()) { out.push({json:{...empty('empty'),raw_email:r}}); continue; }
  let p;
  try { p = JSON.parse(c.trim().replace(/^```(?:json)?\s*/i,'').replace(/```$/,'').trim()); } catch(x){ out.push({json:{...empty('parse_err'),raw_email:r}}); continue; }
  const score = typeof p.score_confiance==='number'?Math.max(0,Math.min(1,p.score_confiance)):0;
  out.push({json:{prospect_nom:p.prospect_nom||null,prospect_email:p.prospect_email||null,prospect_tel:p.prospect_tel||null,bien_reference:p.bien_reference||null,bien_adresse:p.bien_adresse||null,type_demande:T.has(p.type_demande)?p.type_demande:'autre',langue:L.has(p.langue)?p.langue:'fr',message_prospect:p.message_prospect||null,score_confiance:score,draft_reply: score<0.3 ? null : (p.draft_reply||null),raw_email:r}});
}
return out;

const items = $input.all();
const leads = $('Parse & Validate').all();
const out = [];
for (let idx = 0; idx < items.length; idx++) {
  const i = items[idx];
  const sourceIdx = i.pairedItem?.item ?? idx;
  const lead = leads[sourceIdx]?.json;
  if (!lead) continue;
  const body = i.json.body !== undefined ? i.json.body : i.json;
  const dupArray = Array.isArray(body) ? body : (body && body.id ? [body] : []);
  const isDuplicate = dupArray.length > 0 && !!dupArray[0].id;
  out.push({ json: { ...lead, _action: isDuplicate ? 'log_duplicate' : 'insert', _duplicate_id: isDuplicate ? dupArray[0].id : null } });
}
return out;

const items = $input.all();
const leads = $('Parse & Validate').all();
const out = [];
for (let idx = 0; idx < items.length; idx++) {
  const i = items[idx];
  const sourceIdx = i.pairedItem?.item ?? idx;
  const lead = leads[sourceIdx]?.json;
  if (!lead || !lead.draft_reply || !lead.prospect_email) continue;
  out.push(i);
}
return out;

const items = $input.all();
const leads = $('Parse & Validate').all();
const triggers = $('Gmail Trigger').all();
const out = [];
for (let idx = 0; idx < items.length; idx++) {
  const i = items[idx];
  const sourceIdx = i.pairedItem?.item ?? idx;
  const lead = leads[sourceIdx]?.json;
  const trigger = triggers[sourceIdx]?.json;
  if (!lead || !trigger) continue;
  const to = lead.prospect_email;
  const draft = lead.draft_reply;
  const origSubj = (trigger.subject || '').toString();
  const subject = /^re:/i.test(origSubj) ? origSubj : 'Re: ' + origSubj;
  const messageId = trigger.messageId || trigger.id || '';
  const inReplyHeader = messageId ? ('In-Reply-To: ' + messageId + '\r\nReferences: ' + messageId + '\r\n') : '';
  const rfc822 = 'To: ' + to + '\r\n' + 'Subject: ' + subject + '\r\n' + inReplyHeader + 'Content-Type: text/html; charset="UTF-8"\r\nMIME-Version: 1.0\r\n\r\n' + draft;
  const raw = Buffer.from(rfc822, 'utf-8').toString('base64').replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');
  out.push({ json: { raw, threadId: trigger.threadId, _to: to, _subject: subject } });
}
return out;
